payload.arguments:
{"command":"$script = @'
set -eu
src='/volume1/mac/Decor/Generic Decor/_New structure/AA1/16x16/AA166MSFSH06/ART/AA166MSFSH06_16x16x1_Printed Canvas w Foil_Chanel Perfume Bottle Gold Heart_ART.tif'
dir=${src%/*}
parent=${dir%/*}
base=${src##*/}
bak_in_place="$src.bak"
bak_parent="$parent/$base.bak"

printf 'host='; hostname
printf 'src=%s\n' "$src"
printf 'bak_in_place=%s\n' "$bak_in_place"
printf 'bak_parent=%s\n' "$bak_parent"

[ -f "$src" ] || { echo "ERROR: source missing" >&2; exit 1; }
[ ! -e "$bak_in_place" ] || { echo "ERROR: in-place .bak already exists" >&2; exit 1; }
[ ! -e "$bak_parent" ] || { echo "ERROR: parent .bak already exists" >&2; exit 1; }

mv -- "$src" "$bak_in_place"
mv -- "$bak_in_place" "$bak_parent"

echo 'Moved to parent as .bak:'
ls -ld -- "$bak_parent"
'@
$script | ssh edge1 'sh -s'","workdir":"C:\repos\edgesynology2","timeout_ms":30000}

{"command":"$script = @'
set -eu
src='/volume1/mac/Decor/Generic Decor/_New structure/AA1/16x16/AA166MSFSH06/ART/AA166MSFSH06_16x16x1_Printed Canvas w Foil_Chanel Perfume Bottle Gold Heart_ART.tif'
dir=${src%/*}
parent=${dir%/*}
base=${src##*/}
bak_parent="$parent/$base.bak"
plain_parent="$parent/$base"

printf 'host='; hostname
printf 'bak_parent=%s\n' "$bak_parent"
printf 'plain_parent=%s\n' "$plain_parent"
printf 'src=%s\n' "$src"

[ -f "$bak_parent" ] || { echo "ERROR: parent .bak missing" >&2; exit 1; }
[ ! -e "$plain_parent" ] || { echo "ERROR: parent plain file already exists" >&2; exit 1; }
[ ! -e "$src" ] || { echo "ERROR: original destination already exists" >&2; exit 1; }
[ -d "$dir" ] || { echo "ERROR: original directory missing" >&2; exit 1; }

mv -- "$bak_parent" "$plain_parent"
mv -- "$plain_parent" "$src"

echo 'Restored original file:'
stat -- "$src"
'@
$script = $script -replace "`r`n", "`n"
$script | ssh edge1 'sh -s'","workdir":"C:\repos\edgesynology2","timeout_ms":30000}
